import { Component, OnInit } from '@angular/core';
import { ActivatedRoute, Router } from '@angular/router';
import { TeamService } from '../../../../core/services/team.service';
import { AuthService } from '../../../../core/services/auth.service';
import { InvitationsService } from '../../../../core/services/invitations.service';
import { TeamDTO } from '../../../../core/models/team.model';

@Component({
  selector: 'app-team-manage',
  templateUrl: './team-manage.component.html',
  styleUrls: ['./team-manage.component.scss']
})
export class TeamManageComponent implements OnInit {
  team: TeamDTO | null = null;
  isLoading = true;
  errorMessage = '';
  teamId: string = '';
  isEditing = false;
  editedTeamName: string = '';

  // Variabili per gli inviti
  isInviting = false;
  inviteEmail: string = '';
  inviteMessage: string = '';
  inviteError: string = '';

  // Utente corrente
  currentUser: any = null;

  constructor(
    private route: ActivatedRoute,
    private router: Router,
    private teamService: TeamService,
    private authService: AuthService,
    private invitationsService: InvitationsService
  ) {}

  ngOnInit(): void {
    this.authService.currentUser$.subscribe(user => {
      this.currentUser = user;
    });

    this.teamId = this.route.snapshot.paramMap.get('teamId') || '';
    if (this.teamId) {
      this.loadTeamDetails();
    } else {
      this.errorMessage = 'Team ID not provided';
      this.isLoading = false;
    }
  }

  loadTeamDetails(): void {
    this.isLoading = true;
    this.errorMessage = '';

    this.teamService.getTeamDetails(this.teamId).subscribe({
      next: (team) => {
        this.team = team;
        this.editedTeamName = team.nome || '';
        this.isLoading = false;
        console.log('TeamManageComponent - Team loaded:', team);
      },
      error: (error) => {
        console.error('TeamManageComponent - Error loading team:', error);
        this.errorMessage = 'Failed to load team details. Please try again.';
        this.isLoading = false;
      }
    });
  }

  startEditing(): void {
    this.isEditing = true;
    this.editedTeamName = this.team?.nome || '';
  }

  cancelEditing(): void {
    this.isEditing = false;
    this.editedTeamName = this.team?.nome || '';
  }

  saveTeamName(): void {
    if (!this.editedTeamName.trim()) {
      return;
    }

    console.log('TeamManageComponent - Saving team details...');

    const updateRequest = {
      nomeTeam: this.editedTeamName.trim()
    };

    this.teamService.updateTeam(this.teamId, updateRequest).subscribe({
      next: (updatedTeam) => {
        console.log('TeamManageComponent - Team updated successfully:', updatedTeam);
        this.team = updatedTeam;
        this.isEditing = false;
      },
      error: (error) => {
        console.error('TeamManageComponent - Error updating team:', error);
        this.errorMessage = error.error?.message || 'Failed to update team details.';
        this.isEditing = false;
      }
    });
  }

  deleteTeam(): void {
    if (confirm('Are you sure you want to delete this team? This action cannot be undone.')) {
      console.log('TeamManageComponent - Deleting team:', this.teamId);
      this.teamService.abbandonaTeam(this.teamId).subscribe({
        next: () => {
          console.log('TeamManageComponent - Team abandoned successfully');
          const currentUser = this.authService.currentUser;
          if (currentUser) {
            currentUser.ruolo = 'UTENTE_SENZA_TEAM';
            this.authService.updateCurrentUserLocally(currentUser);
          }
          this.router.navigate(['/teams']);
        },
        error: (error) => {
          console.error('TeamManageComponent - Error abandoning team:', error);
          this.errorMessage = error.error?.message || 'Failed to delete team. Please try again.';
        }
      });
    }
  }

  goBack(): void {
    this.router.navigate(['/teams', this.teamId]);
  }

  transferLeadership(newLeaderId: string, newLeaderName: string): void {
    if (confirm(`Are you sure you want to make ${newLeaderName} the new Team Leader? You will become a regular member.`)) {
      console.log('TeamManageComponent - Transferring leadership to:', newLeaderId);
      this.teamService.transferLeadership(this.teamId, newLeaderId).subscribe({
        next: (updatedTeam) => {
          console.log('TeamManageComponent - Leadership transferred successfully');
          this.team = updatedTeam;

          // Update current user role locally since they are no longer the leader
          const currentUser = this.authService.currentUser;
          if (currentUser) {
            currentUser.ruolo = 'MEMBRO_TEAM';
            this.authService.updateCurrentUserLocally(currentUser);
          }
        },
        error: (error) => {
          console.error('TeamManageComponent - Error transferring leadership:', error);
          this.errorMessage = error.error?.message || 'Failed to transfer leadership. Please try again.';
        }
      });
    }
  }

  inviteMembers(): void {
    // Al click mostriamo il form per inserire l'email
    this.isInviting = !this.isInviting;
    this.inviteEmail = '';
    this.inviteMessage = '';
    this.inviteError = '';
  }

  cancelInvite(): void {
    this.isInviting = false;
    this.inviteEmail = '';
    this.inviteMessage = '';
    this.inviteError = '';
  }

  sendInvitation(): void {
    if (!this.inviteEmail.trim()) {
      this.inviteError = 'Please enter an email address.';
      return;
    }

    this.inviteError = '';
    this.inviteMessage = '';

    const request = {
      teamId: this.teamId,
      emailDestinatario: this.inviteEmail.trim()
    };

    console.log('TeamManageComponent - Sending invitation to:', request.emailDestinatario);

    this.invitationsService.sendInvitation(request).subscribe({
      next: (response) => {
        console.log('TeamManageComponent - Invitation sent successfully', response);
        this.inviteMessage = 'Invitation sent successfully!';
        this.inviteEmail = ''; // Pulisci la form

        // Chiudi il form di invito dopo qualche secondo per conferma visiva
        setTimeout(() => {
          this.isInviting = false;
          this.inviteMessage = '';
        }, 3000);
      },
      error: (error) => {
        console.error('TeamManageComponent - Error sending invitation:', error);
        this.inviteError = error.error?.message || 'Failed to send invitation. Please check the email and try again.';
      }
    });
  }
}
<div class="team-manage-container">
  <!-- Loading State -->
  <div class="loading-state" *ngIf="isLoading">
    <div class="loading-spinner">
      <div class="spinner"></div>
      <p>Loading team management...</p>
    </div>
  </div>

  <!-- Error State -->
  <div class="error-state" *ngIf="errorMessage">
    <div class="error-card">
      <div class="error-icon">⚠️</div>
      <h3>Oops! Something went wrong</h3>
      <p>{{ errorMessage }}</p>
      <button class="btn-secondary" (click)="loadTeamDetails()">Try Again</button>
      <button class="btn-primary" (click)="goBack()">Go Back</button>
    </div>
  </div>

  <!-- Team Management -->
  <div class="team-management" *ngIf="!isLoading && !errorMessage && team">
    <div class="page-header">
      <button class="btn-secondary back-button" (click)="goBack()">
        <span>←</span>
        <span>Back to Team Details</span>
      </button>
      <h1 class="page-title">Manage Team</h1>
    </div>

    <div class="management-sections">
      <!-- Team Information -->
      <div class="management-section">
        <h2>Team Information</h2>
        <div class="team-info-card">
          <div class="team-name-section">
            <label>Team Name</label>
            <div class="name-edit-container" *ngIf="!isEditing; else editingName">
              <span class="team-name">{{ team.nome || 'Unknown Team' }}</span>
              <button class="btn-primary" (click)="startEditing()">
                <span>✏️</span>
                <span>Edit</span>
              </button>
            </div>
            <ng-template #editingName>
              <div class="name-edit-form">
                <input 
                  type="text" 
                  [(ngModel)]="editedTeamName"
                  class="team-name-input"
                  placeholder="Enter team name"
                  maxlength="50"
                />
                <div class="edit-actions">
                  <button class="btn-primary save-btn" (click)="saveTeamName()" [disabled]="!editedTeamName.trim()">
                    <span>💾</span>
                    <span>Save</span>
                  </button>
                  <button class="btn-secondary cancel-btn" (click)="cancelEditing()">
                    <span>❌</span>
                    <span>Cancel</span>
                  </button>
                </div>
              </div>
            </ng-template>
          </div>

          <div class="team-stats-section">
            <div class="stat-item">
              <span class="stat-label">Team Members</span>
              <span class="stat-value">{{ team.membriIds.length || 0 }}</span>
            </div>
            <div class="stat-item">
              <span class="stat-label">Created</span>
              <span class="stat-value">{{ team.dataCreazione ? (team.dataCreazione | date:'mediumDate') : 'Unknown' }}</span>
            </div>
          </div>
        </div>
      </div>

      <!-- Team Members -->
      <div class="management-section">
        <div class="section-header">
          <h2>Team Members</h2>
          <button class="btn-primary" (click)="inviteMembers()" *ngIf="!isInviting">
            <span>➕</span>
            <span>Invite Members</span>
          </button>
        </div>

        <div class="invitation-form-container" *ngIf="isInviting">
          <div class="invitation-form-card">
            <h3>Invite a New Member</h3>
            <p>Enter the email address of the user you would like to invite.</p>

            <div class="form-group">
              <input 
                type="email" 
                [(ngModel)]="inviteEmail" 
                class="invite-email-input"
                placeholder="user@example.com"
                (keyup.enter)="sendInvitation()"
              />
            </div>

            <!-- Messaggi di feedback -->
            <div class="alert alert-success mt-3" *ngIf="inviteMessage">
              {{ inviteMessage }}
            </div>
            <div class="alert alert-danger mt-3" *ngIf="inviteError">
              {{ inviteError }}
            </div>

            <div class="invite-actions mt-3">
              <button class="btn-primary" (click)="sendInvitation()" [disabled]="!inviteEmail.trim()">
                <span>✉️</span>
                <span>Send Invitation</span>
              </button>
              <button class="btn-secondary" (click)="cancelInvite()">
                <span>❌</span>
                <span>Cancel</span>
              </button>
            </div>
          </div>
        </div>
        <div class="members-list">
          <div class="member-item" *ngFor="let memberName of team.membriNomi || []; let i = index">
            <div class="member-avatar">
              {{ memberName.charAt(0).toUpperCase() }}
            </div>
            <div class="member-info">
              <span class="member-name">{{ memberName }}</span>
              <span class="member-role" *ngIf="team.membriIds && team.leaderId && team.membriIds[i] === team.leaderId">👑 Team Leader</span>
              <span class="member-role" *ngIf="!(team.membriIds && team.leaderId && team.membriIds[i] === team.leaderId)">👤 Team Member</span>
            </div>

            <div class="member-actions" *ngIf="team.leaderId === currentUser?.id && team.membriIds && team.membriIds[i] !== team.leaderId">
              <button class="btn-success btn-small" (click)="transferLeadership(team.membriIds[i], memberName)" title="Make Team Leader">
                <span>👑</span>
                <span>Make Leader</span>
              </button>
            </div>
          </div>
        </div>
      </div>

      <!-- Danger Zone -->
      <div class="management-section danger-zone">
        <h2>Danger Zone</h2>
        <div class="danger-card">
          <div class="danger-info">
            <h3>Delete Team</h3>
            <p>Once you delete a team, there is no going back. Please be certain.</p>
          </div>
          <button class="btn-danger" (click)="deleteTeam()">
            <span>🗑️</span>
            <span>Delete Team</span>
          </button>
        </div>
      </div>
    </div>
  </div>
</div>
